@namespace Lumeo

@{
    var context = new AlertDialogContext(EffectiveOpen, EventCallback.Factory.Create<bool>(this, SetOpen), _titleId, _descriptionId, TryDismiss);
}

<CascadingValue Value="context" IsFixed="false">
    @ChildContent
</CascadingValue>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public bool Open { get; set; }
    [Parameter] public EventCallback<bool> OpenChanged { get; set; }

    /// <summary>
    /// Uncontrolled initial open state (Radix <c>defaultOpen</c>). Used only
    /// when the consumer does NOT bind <see cref="Open"/>: the dialog then owns
    /// its open state internally, seeded from this value. Ignored when
    /// <see cref="Open"/> is supplied (controlled mode).
    /// </summary>
    [Parameter] public bool DefaultOpen { get; set; }

    /// <summary>
    /// Fires before any user-initiated dismiss (Escape key, the Cancel
    /// button, or the Action button). Set
    /// <see cref="DismissEventArgs.Cancel"/> to <c>true</c> to abort. The
    /// <see cref="DismissEventArgs.Reason"/> tells you which path fired
    /// (<c>"escape"</c>, <c>"cancel"</c>, <c>"action"</c>).
    /// </summary>
    [Parameter] public EventCallback<DismissEventArgs> OnBeforeClose { get; set; }

    [Obsolete("Use Open instead. IsOpen will be removed in a future release.")]
    [Parameter] public bool IsOpen { get => Open; set => Open = value; }

    [Obsolete("Use OpenChanged instead. IsOpenChanged will be removed in a future release.")]
    [Parameter] public EventCallback<bool> IsOpenChanged { get => OpenChanged; set => OpenChanged = value; }

    private readonly string _titleId = LumeoIds.New("alertdialog-title");
    private readonly string _descriptionId = LumeoIds.New("alertdialog-desc");

    // Controlled-vs-uncontrolled disambiguation: a bool param can't be
    // "undefined", so we inspect which parameters the consumer actually supplied.
    private bool _controlled;
    private bool _open;

    private bool EffectiveOpen => _controlled ? Open : _open;

    public override Task SetParametersAsync(ParameterView parameters)
    {
        // The legacy IsOpen alias is obsolete but still a valid bound parameter,
        // so we must honour it when deciding controlled-ness (suppress CS0618 for
        // the nameof — we're intentionally probing the alias).
#pragma warning disable CS0618
        _controlled = parameters.TryGetValue<bool>(nameof(Open), out _)
            || parameters.TryGetValue<bool>(nameof(IsOpen), out _)
            || OpenChanged.HasDelegate;
#pragma warning restore CS0618
        return base.SetParametersAsync(parameters);
    }

    protected override void OnInitialized()
    {
        if (!_controlled) _open = DefaultOpen;
    }

    private async Task SetOpen(bool value)
    {
        _open = value;
        Open = value;
        await OpenChanged.InvokeAsync(value);
        // Re-render so the cascaded context picks up EffectiveOpen — the
        // Escape/Cancel paths reach here via TryDismiss as a direct method call,
        // so an uncontrolled dialog (no OpenChanged) needs this to close.
        StateHasChanged();
    }

    private async Task<bool> TryDismiss(string reason)
    {
        if (OnBeforeClose.HasDelegate)
        {
            var args = new DismissEventArgs { Reason = reason };
            await OnBeforeClose.InvokeAsync(args);
            if (args.Cancel) return false;
        }
        await SetOpen(false);
        return true;
    }

    public record AlertDialogContext(bool IsOpen, EventCallback<bool> SetOpen, string TitleId, string DescriptionId, Func<string, Task<bool>> TryDismiss);
}

@namespace Lumeo

<button class="@CssClass" disabled="@IsLoading" @onclick="DoAction" @attributes="AdditionalAttributes">
    @if (IsLoading)
    {
        <Spinner Class="h-4 w-4 me-2" />
    }
    @ChildContent
</button>

@code {
    [CascadingParameter] public AlertDialog.AlertDialogContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public EventCallback OnAction { get; set; }
    [Parameter] public bool IsLoading { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("inline-flex items-center justify-center whitespace-nowrap rounded-md text-sm font-medium transition-colors focus-visible:outline-none bg-destructive text-destructive-foreground shadow hover:bg-destructive/90 h-9 px-4 py-2 disabled:pointer-events-none disabled:opacity-50", Class);

    private async Task DoAction()
    {
        await OnAction.InvokeAsync();
        if (!IsLoading)
        {
            // Route the auto-close through the gate so OnBeforeClose can
            // veto with reason="action" (e.g. validation failed mid-action).
            // The OnAction handler itself still ran — only the close is
            // guarded.
            await Context.TryDismiss("action");
        }
    }
}

@namespace Lumeo

@* data-lumeo-initial-focus — AlertDialogContent points its focus trap at this
   marker so initial focus lands on the LEAST destructive action (this Cancel
   button) rather than the first focusable element, per the WAI-ARIA
   alertdialog pattern / Radix behaviour. *@
<button class="@CssClass" data-lumeo-initial-focus @onclick="Cancel" @attributes="AdditionalAttributes">
    @ChildContent
</button>

@code {
    [CascadingParameter] public AlertDialog.AlertDialogContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("inline-flex items-center justify-center whitespace-nowrap rounded-md text-sm font-medium transition-colors focus-visible:outline-none border border-input bg-background shadow-sm hover:bg-accent hover:text-accent-foreground h-9 px-4 py-2 mt-2 sm:mt-0", Class);

    // Route through TryDismiss so OnBeforeClose handlers can guard the
    // cancel button (reason="cancel") just like Escape / Action paths.
    private async Task Cancel() => await Context.TryDismiss("cancel");
}

@namespace Lumeo
@using Lumeo.Services
@implements IAsyncDisposable

@if (Context.IsOpen)
{
    <div class="fixed inset-0 flex items-center justify-center" style="z-index:@BackdropZ">
        @* Backdrop — theme-aware --color-overlay-backdrop token via inline style
           (see DialogContent for why inline style not a Tailwind utility). *@
        <div class="fixed inset-0 animate-fade-in" style="background-color:var(--color-overlay-backdrop);z-index:@BackdropZ"></div>
        @* @onkeydown:stopPropagation — keys handled inside this modal must not
           bubble into ancestor overlays (an Escape would cascade-close them).
           See DialogContent for the full rationale. *@
        <div id="@_contentId" class="@CssClass" style="z-index:@ContentZ" role="alertdialog" aria-modal="true" aria-labelledby="@Context.TitleId" aria-describedby="@Context.DescriptionId" @onkeydown="HandleKeyDown" @onkeydown:stopPropagation tabindex="-1" @attributes="AdditionalAttributes">
            @ChildContent
        </div>
    </div>
}

@inject IComponentInteropService Interop

@code {
    [CascadingParameter] public AlertDialog.AlertDialogContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    /// <summary>Backdrop z-index. Content sits at <c>ZIndex + 1</c>. Defaults
    /// to <see cref="OverlayService.BaseZIndex"/>; <see cref="OverlayProvider"/>
    /// supplies an incrementing value per nested overlay.</summary>
    [Parameter] public int ZIndex { get; set; } = OverlayService.BaseZIndex;
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _contentId = LumeoIds.New("alertdialog");
    private bool _wasOpen;

    private int BackdropZ => ZIndex;
    private int ContentZ => ZIndex + 1;

    private string CssClass => Cx.Merge("relative grid w-full max-w-lg gap-4 bg-background p-6 shadow-lg animate-zoom-in sm:rounded-lg", Class);

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (Context.IsOpen && !_wasOpen)
        {
            await Interop.LockScroll();
            // Initial focus goes to the least destructive action — the Cancel
            // button carries the data-lumeo-initial-focus marker (WAI-ARIA
            // alertdialog pattern). Falls back to the first focusable element
            // when no AlertDialogCancel is present.
            await Interop.SetupFocusTrap(_contentId, "[data-lumeo-initial-focus]");
            _wasOpen = true;
        }
        else if (!Context.IsOpen && _wasOpen)
        {
            await Cleanup();
            _wasOpen = false;
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Escape")
        {
            await Context.TryDismiss("escape");
        }
    }

    private async Task Cleanup()
    {
        try
        {
            await Interop.RemoveFocusTrap(_contentId);
            await Interop.UnlockScroll();
        }
        catch (JSDisconnectedException) { }
    }

    public async ValueTask DisposeAsync()
    {
        if (_wasOpen)
        {
            await Cleanup();
        }
    }
}

